import importlib

def import_objects_by_path(object_paths):
    "Import Python objects by their paths."
    objects = []
    for i in range(len(object_paths)):
        module_name, object_name = object_paths[i].rsplit('.',1)
        module = importlib.import_module(module_name)
        objects.append(getattr(module, object_name))
    return objects



