#@njit
def extract_objective_data(data, trial_mask):
        
    # construct subject-specific trial mask, quitting if no trials are selected
    trial_list_lengths = data['listLength'].flatten()
    trial_count = np.sum(trial_mask)
    if trial_count == 0:
        raise ValueError("No trials selected for fitting")
    
    # check if presentations have within-trial repetitions
    trial_list_lengths = trial_list_lengths[trial_mask]
    list_lengths = np.unique(trial_list_lengths)
    presentations = data['pres_itemnos'][trial_mask]
    has_repetitions = not (
        presentations[:, :list_lengths[0]] == np.arange(list_lengths[0])+1).all()

    # mask variables by trial mask then split by list length
    trials = split_by_unique_list_lengths(
        data['recalls'][trial_mask], trial_list_lengths)
    presentations = split_by_unique_list_lengths(
       presentations, trial_list_lengths)
    pres_string_ids = None
    if 'pres_itemids' in data:
        pres_string_ids = split_by_unique_list_lengths(
            data['pres_itemids'][trial_mask], trial_list_lengths)
    # cycles = None
    # if 'cycles' in data:
    #     cycles = split_by_unique_list_lengths(
    #         data['cycles'][trial_mask], trial_list_lengths)
    # trial_mask = split_by_unique_list_lengths(trial_mask, trial_list_lengths)

    return trials, list_lengths, presentations, pres_string_ids, has_repetitions

# %% ../src/evaluation/00_Evaluation.ipynb 4
import numpy as np

def model_weights(positive_log_likelihoods, number_parameters, N):
    AIC = 2 * positive_log_likelihoods + 2 * number_parameters
    AICc = AIC #+ (2*np.power(number_parameters, 2) + 2 * number_parameters) / (N - number_parameters - 2)
    AICd = AIC - np.min(AICc)
    #return AICd
    AICw = np.exp(-.5 * AICd) / np.sum(np.exp(-.5 * AICd))
    return AICw

