import pandas as pd

def modelwise_fit_to_dataframe(modelwise_fitted_parameters):

    # # flatten fixed and free parameters
    # for key in parameter_list[-1]['fixed']:
    #     parameter_list[-1][key] = parameter_list[-1]['fixed'][key]
    # # for key in parameter_list[-1]['free']:
    # #     parameter_list[-1][key] = parameter_list[-1]['free'][key]
    # del parameter_list[-1]['fixed']
    # del parameter_list[-1]['free']

    all_model_individual_fits = []
    for model_result in modelwise_fitted_parameters:
        model_individual_fits = []
        for fitted_parameters in model_result:
            
            for key in fitted_parameters['fixed']:
                fitted_parameters[key] = fitted_parameters['fixed'][key]
            del fitted_parameters['fixed']
            del fitted_parameters['free']

            model_individual_fits.append(pd.DataFrame.from_dict(fitted_parameters, orient='index').T)

        model_individual_fits = pd.concat(model_individual_fits, ignore_index=True)
        all_model_individual_fits.append(model_individual_fits)

    individual_fits = pd.concat(all_model_individual_fits, ignore_index=True)
    cols = individual_fits.columns.drop('model')
    individual_fits[cols] = individual_fits[cols].apply(pd.to_numeric, errors='coerce')
    return individual_fits


def summarize_parameter_distribution(individual_fits):

    summary = individual_fits.groupby('model').describe()
    summary = summary.drop(columns=['subject', 'trial_count'])
    summary = summary.drop(axis=1, level=1, columns=['count', '25%', '50%', '75%', 'min', 'max']).reset_index().T
    summary.columns = summary.loc['model'].values[0].tolist()
    summary = summary.drop(axis=0, index='model', level=0)
    summary = summary.rename(columns=lambda s: s.replace('_', ' '), index=lambda s: s.replace('_', ' '))

    return summary.style.to_latex(), summary

def summarize_fits(individual_fits):
    return pd.DataFrame(group.describe().rename(columns={'likelihood':name}).squeeze()
            for name, group in individual_fits[['model', 'likelihood']].groupby('model')).T.to_markdown()

