import seaborn as sns


def modelwise_aicw(individual_fits, data, trial_mask, free_parameters):
    aicw = {'Model': [], 'Subject': [], 'AICw': []}

    model_names = [model for model in pd.unique(individual_fits.model)]
    trial_list_lengths = data['listLength'][trial_mask]
    unique_list_lengths = np.unique(trial_list_lengths)
    total_nlns = np.zeros(len(model_names))
    for subject_index, subject in enumerate(pd.unique(individual_fits.subject)):

        extra_mask = (data['subject'] == subject).flatten()
        extra_mask = [extra_mask[trial_list_lengths == list_length] for list_length in unique_list_lengths]
        subject_specific_trial_mask = [np.logical_and(extra_mask[i], trial_mask[i]) for i in range(len(unique_list_lengths))]

        nlnLs = []
        for model_index, model_name in enumerate(model_names):
            nlnLs.append(
                individual_fits[individual_fits.model == model_name].likelihood.values[subject_index])
        nlnLs = np.array(nlnLs)
        total_nlns += nlnLs
        
        weights = model_weights(nlnLs, len(free_parameters[model_index]), np.sum(
                        [np.sum(subject_specific_trial_mask[i]) for i in range(len(subject_specific_trial_mask))]))
        #print(weights)
        for model_index, model_class in enumerate(model_names):
            aicw['Model'].append(model_names[model_index])
            aicw['Subject'].append(subject)
            aicw['AICw'].append(weights[model_index])

    aicw = pd.DataFrame(data=aicw)
    total_aicw = model_weights(total_nlns, len(free_parameters[model_index]),np.sum(
                        [np.sum(trial_mask[i]) for i in range(len(trial_mask))]))
    return aicw, total_aicw

def plot_modelwise_aicw(individual_fits, data, trial_mask, free_parameters):
    aicw, _ = modelwise_aicw(individual_fits, data, trial_mask, free_parameters)
    return sns.pointplot(x="Model", y="AICw", data=aicw, join=False)

